                else
                    writer.WriteNull("error_text");

            if (smsReceipt.CustomStringOption.IsSet)
                if (smsReceipt.CustomStringOption.Value != null)
                    writer.WriteString("custom_string", smsReceipt.CustomString);
                else
                    writer.WriteNull("custom_string");

            if (smsReceipt.SubaccountIdOption.IsSet)
                writer.WriteNumber("subaccount_id", smsReceipt.SubaccountIdOption.Value!.Value);

            if (smsReceipt.MessageTypeOption.IsSet)
                writer.WriteString("message_type", smsReceipt.MessageType);

            if (smsReceipt.DigitsOption.IsSet)
                writer.WriteNumber("digits", smsReceipt.DigitsOption.Value!.Value);
        }
    }
}
